const cache = new Map();
const registry = new FinalizationRegistry((key) => cache.delete(key));

function get(key) {
  const ref = cache.get(key);
  if (ref) {
    const v = ref.deref();
    if (v) return v;
    cache.delete(key);
  }
  return null;
}
function set(key, value) {
  cache.set(key, new WeakRef(value));
  registry.register(value, key);
}

