import LRUCache from 'lru-cache';

const columnCache = new LRUCache<string, readonly string[]>({max: 500, ttl: 60_000});

export async function getColumns(client, tableName: string) {
  const cached = columnCache.get(tableName);
  if (cached) return cached;
  const {rows} = await client.query(
    `select attname
       from pg_attribute
      where attrelid = $1::regclass
        and attnum > 0
        and not attisdropped
      order by attnum`,
    [tableName],
  );
  const columns = rows.map((row) => row.attname);
  columnCache.set(tableName, columns);
  return columns;
}

