import {onLCP} from 'web-vitals/attribution';
onLCP((metric) => {
  const att = metric.attribution;
  sendRUM({
    metric: 'LCP', value: metric.value,
    element: att?.element, // selector
    url: att?.url, // resource
    timeToFirstByte: att?.timeToFirstByte,
    resourceLoadDelay: att?.resourceLoadDelay,
    resourceLoadDuration: att?.resourceLoadDuration,
    elementRenderDelay: att?.elementRenderDelay
  });
});
